  protected override async doLoad(context: Context): Promise<LoadResult> {
    console.log('[meridianlifesupportMFE][doLoad] loading remoteEntry=%s', context.inputs?.remoteEntry ?? '<from manifest>');
    const result = await super.doLoad(context);
    if (result.status === 'loaded') {
      console.log('[meridianlifesupportMFE][doLoad] ready — components=%o duration=%dms', result.availableComponents, result.duration);
    } else {
      console.error('[meridianlifesupportMFE][doLoad] failed — status=%s error=%s', result.status, (result.error as Error | undefined)?.message);
    }
    return result;
  }

  protected override async doRender(context: Context): Promise<RenderResult> {
    console.log('[meridianlifesupportMFE][doRender] rendering component=%s containerId=%s', context.inputs?.component ?? '<auto>', context.inputs?.containerId ?? '<auto>');
    const result = await super.doRender(context);
    console.log('[meridianlifesupportMFE][doRender] result=%s duration=%dms', result.status, result.duration);
    return result;
  }

  /**
   * doQuery — routes mfe.query() calls to the BFF connector.
   *
   * Reads context.inputs.document + variables and dispatches via the generated
   * bff.ts connector. The BFF URL is resolved automatically from
   * manifest.endpoint + data.serve.endpoint (e.g. http://localhost:5003/graphql).
   * Pass context.inputs.bffUrl to override when the shell is on a different origin.
   *
   * Re-generated on every `remote:generate` run — do not edit by hand.
   */
  protected override async doQuery(context: Context): Promise<QueryResult> {
    const { document, variables } = (context.inputs ?? {}) as {
      document: string;
      variables?: Record<string, unknown>;
    };
    try {
      const data = await bffQuery(document, variables, {
        ...(context.jwt ? { Authorization: `Bearer ${context.jwt}` } : {}),
        ...(context.requestId ? { 'X-Request-ID': context.requestId } : {}),
      });
      return { data };
    } catch (err) {
      return { data: null, errors: [{ message: (err as Error).message }] };
    }
  }

  // ---------------------------------------------------------------------------
