  // ---------------------------------------------------------------------------

  /**
   * loadDomainComponent
   * @description Resolves a domain capability name to its Angular standalone component.
   * Called by AngularRemoteMFE.doRender() — do not call directly.
   */
  protected override async loadDomainComponent(name: string): Promise<any> {
    switch (name) {

      case 'TelemetryDashboard':
        return import('../../features/TelemetryDashboard/TelemetryDashboard.component').then(
          (m: any) => m['TelemetryDashboardComponent'] ?? m.default
        );

      case 'ModuleStatus':
        return import('../../features/ModuleStatus/ModuleStatus.component').then(
          (m: any) => m['ModuleStatusComponent'] ?? m.default
        );

      case 'AlertsFeed':
        return import('../../features/AlertsFeed/AlertsFeed.component').then(
          (m: any) => m['AlertsFeedComponent'] ?? m.default
        );

      default:
        throw new Error(`[meridianlifesupportMFE] loadDomainComponent: unknown component "${name}"`);
    }
  }

